export const likedArticles = [
  createArticle({
    pageid: 202,
    title: 'Bioluminescent bay',
    extract:
      'A protected lagoon filled with dinoflagellates glows electric blue at night, creating a shoreline that looks illuminated from beneath the water.',
    accent: '#0ea5e9',
  }),
  createArticle({
